// Extraer mensajes del body
const body = $input.first().json.body ?? $input.first().json;
const messages = body.messages ?? [];

// Validar que hay mensajes
if (!messages.length) {
  throw new Error('No messages provided');
}

// Contar mensajes del usuario para contexto
const userMessages = messages.filter(m => m.role === 'user');
const lastUserMsg = userMessages[userMessages.length - 1]?.content ?? '';

// Detectar señales de interes alto (para logging de leads)
const interestKeywords = ['precio', 'costo', 'cuanto', 'contratar', 'activar', 'comprar', 'plan', 'demo', 'prueba', 'reservar', 'quiero', 'necesito'];
const isHighInterest = interestKeywords.some(kw => lastUserMsg.toLowerCase().includes(kw));

return [{
  json: {
    messages,
    lastUserMsg,
    isHighInterest,
    userMessageCount: userMessages.length,
    timestamp: new Date().toISOString()
  }
}];

// Extraer respuesta de OpenAI
const openaiResponse = $input.first().json;
const assistantMessage = openaiResponse.choices?.[0]?.message?.content ?? 'Ups, hubo un problema. Escribinos por WhatsApp: https://wa.me/5493437527193';
const tokens = openaiResponse.usage ?? { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 };

// Obtener contexto del nodo anterior (prepare-messages)
const prepData = $('Preparar mensajes').first().json;

return [{
  json: {
    message: assistantMessage,
    isHighInterest: prepData.isHighInterest,
    userMessageCount: prepData.userMessageCount,
    lastUserMsg: prepData.lastUserMsg,
    tokens,
    timestamp: prepData.timestamp
  }
}];
